import express from "express";

// src/modules/meals/meals.service.ts
var getAllMeals = async (query) => {
  const { cuisine, dietary, minPrice, maxPrice, providerId } = query;
  const whereCondition = {};
  if (cuisine) whereCondition.cuisine = cuisine;
  if (dietary)
    whereCondition.dietary = {
      hasSome: Array.isArray(dietary) ? dietary : [dietary],
    };
  if (minPrice || maxPrice) {
    whereCondition.price = {};
    if (minPrice) whereCondition.price.gte = Number(minPrice);
    if (maxPrice) whereCondition.price.lte = Number(maxPrice);
  }
  if (providerId) whereCondition.providerId = providerId;
  return await prisma.meal.findMany({
    where: whereCondition,
    include: {
      provider: true,
      category: true,
    },
  });
};
var getMealById = async (id) => {
  return await prisma.meal.findUnique({
    where: { id },
    include: {
      provider: true,
      category: true,
    },
  });
};
var createMeal = async (data, userId) => {
  const provider = await prisma.providerProfile.findUnique({
    where: { userId },
  });
  if (!provider) {
    throw new Error("provider not found");
  }
  const result = await prisma.meal.create({
    data: {
      ...data,
      providerId: provider.id,
    },
  });
  return result;
};
var updateMeal = async (mealId, data, userId) => {
  const provider = await prisma.providerProfile.findUnique({
    where: { userId },
  });
  if (!provider) {
    throw new Error("provider not found");
  }
  const meal = await prisma.meal.findUnique({
    where: { id: mealId },
  });
  if (!meal || meal.providerId !== provider.id) {
    throw new Error("Unathorized");
  }
  return prisma.meal.update({
    where: { id: mealId },
    data,
  });
};
var deleteMeal = async (mealId, userId) => {
  const provider = await prisma.providerProfile.findUnique({
    where: { userId },
  });
  if (!provider) {
    throw new Error("provider not found");
  }
  const meal = await prisma.meal.findUnique({
    where: { id: mealId },
  });
  if (!meal || meal.providerId !== provider.id) {
    throw new Error("Unauthorized");
  }
  return prisma.meal.delete({
    where: { id: mealId },
  });
};
var getMyMeals = async (userId) => {
  const provider = await prisma.providerProfile.findUnique({
    where: { userId },
  });
  if (!provider) {
    throw new Error("provider not found");
  }
  const totalMeals = await prisma.meal.count({
    where: { providerId: provider.id },
  });
  return {
    totalMeals,
    meals: await prisma.meal.findMany({
      where: { providerId: provider.id },
    }),
  };
};
var mealService = {
  getAllMeals,
  getMealById,
  createMeal,
  updateMeal,
  deleteMeal,
  getMyMeals,
};

