var createOrder = async (payload, userId) => {
  const { items, address } = payload;
  let totalPrice = 0;
  const orderItemsData = await Promise.all(
    items.map(async (item) => {
      const meal = await prisma.meal.findUnique({
        where: { id: item.mealId },
      });
      if (!meal) throw new Error("Meal not found");
      totalPrice += meal.price * item.quantity;
      return {
        mealId: item.mealId,
        quantity: item.quantity,
      };
    }),
  );
  const order = await prisma.order.create({
    data: {
      userId,
      totalPrice,
      address,
      items: {
        create: orderItemsData,
      },
    },
    include: {
      items: true,
    },
  });
  return order;
};
var getMyOrders = async (userId) => {
  return await prisma.order.findMany({
    where: { userId },
    include: {
      items: {
        include: {
          meal: true,
        },
      },
    },
    orderBy: { createdAt: "desc" },
  });
};
var getAllOrders = async () => {
  return await prisma.order.findMany({
    include: {
      items: {
        include: {
          meal: true,
        },
      },
    },
    orderBy: { createdAt: "desc" },
  });
};
var getProviderOrders = async (userId) => {
  const provider = await prisma.providerProfile.findUnique({
    where: { userId },
  });
  if (!provider) throw new Error("Provider not found");
  const whereCondition = {
    items: {
      some: {
        meal: { providerId: provider.id },
      },
    },
  };
  const [orders, totalCount] = await Promise.all([
    prisma.order.findMany({
      where: whereCondition,
      include: {
        items: {
          include: {
            meal: true,
          },
        },
        user: true,
      },
    }),
    prisma.order.count({
      where: whereCondition,
    }),
  ]);
  return { orders, totalCount };
};
var updateOrderStatus = async (orderId, status) => {
  return prisma.order.update({
    where: { id: orderId },
    data: { status },
  });
};
